# Module providing geometric shapes and interfaces

interface IDrawable:
    def draw(self) -> str:
        ...

    def get_area(self) -> float:
        ...

@abstract
class Shape(IDrawable):
    color: str

    def __init__(self, color: str):
        self.color = color

    @abstract
    def get_area(self) -> float:
        ...

    @virtual
    def draw(self) -> str:
        return f"Drawing a {self.color} shape"

class Circle(Shape):
    radius: float

    def __init__(self, color: str, radius: float):
        super().__init__(color)
        self.radius = radius

    @override
    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing a {self.color} circle with radius {self.radius}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, color: str, width: float, height: float):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def draw(self) -> str:
        return f"Drawing a {self.color} rectangle {self.width}x{self.height}"

